import type { WithRef } from '@andes/common';
import type { FunctionComponent, ReactElement } from 'react';
import type { DotSpecificProps, PillIconSpecificProps } from '@andes/badge';

type Hierarchy = HierarchyValueDeprecate | 'loud' | 'mute' | 'quiet';

type HierarchyValueDeprecate = 'neutral';

type Modifier = 'circle' | 'square';

type Size = '16' | '24' | '32' | '40' | '48' | '56' | '64' | '72' | '80' | '96';

type Type = 'grid' | 'stacked';

type BackgroundType = 'complexBackground' | 'default';

export type Color = {
  backgroundColor?: string;
  borderColor?: string;
  color?: string;
};

type ThumbnailProps = WithRef<HTMLDivElement> & {
  /**
   * Determines the background type where is placed the thumbnail.
   * It's used when the thumbnail is placed over a colored surface.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   * @default 'default'
   */
  backgroundType?: BackgroundType;

  /**
   * Badge support. This can be Dot or Pill.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   */
  badge?: ReactElement<DotSpecificProps | PillIconSpecificProps>;

  children: ReactElement;

  /**
   * Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   */
  className?: string;

  /**
   * Custom color definition.
   */
  color?: Color;

  /**
   * Whether the thumbnail should be disabled, it is only supported on the icon content.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   * @default false
   */
  disabled?: boolean;

  /**
   * Styles of the Thumbnail, it is only supported on the icon content.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   * @default 'mute'
   */
  hierarchy?: Hierarchy;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   */
  id?: string;

  /**
   * Type of the thumbnail, it can be `circle` or `square`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   * @default 'circle'
   */
  modifier?: Modifier;

  /**
   * Thumbnail size. Available values are: `'16'`, `'24'`, `'32'`, `'40'`, `'48'`, `'56'`, `'64'`, `'72'`, `'80'`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   * @default '48'
   */
  size?: Size;

  /**
   * A description needed in all types of thumbnails for screen readers and for displaying an alternative text when you hover over thumbnail.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
   */
  srLabel?: string;
};

type ThumbnailMultipleProps = WithRef<HTMLDivElement> & {
  /**
   * Custom content, should be a collection of `<Thumbnail>`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
   */
  children: ReactElement;

  /**
   * Custom class.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
   */
  className?: string;

  /**
   * Container size. For type `grid`, the accepted sizes are: `'40'`, `'48'`, `'56'`, `'64'`, `'72'`, `'80'`. For type `stacked`, also the sizes `'24'`, `'32'` are accepted.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
   * @default '56'
   */
  containerSize?: Exclude<Size, '16' | '96'>;

  /**
   * Unique identifier.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
   */
  id?: string;

  /**
   * Type of the thumbnail, it can be `circle` or `square`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
   * @default 'circle'
   */
  modifier?: Modifier;

  /**
   * Indicates the number of elements that overflow.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
   */
  overflow?: number;

  /**
   * Type of the container layout, could be `grid` or `stacked`.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
   * @default 'grid'
   */
  type?: Type;
};

/**
 * Thumbnail Component, can be used with an image, an icon, text or a custom node.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/55eb4c-thumbnail/b/26f535 | UI Specs}
 * @example
 * import { Thumbnail } from '@andes/thumbnail';
 *
 * const MyComponent = () => (
 *   <Thumbnail>
 *     <img alt="avatar" src="https://http2.mlstatic.com/path/to/some/image.webp" />
 *   </Thumbnail>
 * );
 */
export const Thumbnail: FunctionComponent<ThumbnailProps>;

/**
 * Thumbnail Multiple is a container meant to be used with `@andes/thumbnail` to display various thumbnail.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/thumbnail#props-1 | Documentation}
 * @see {@link https://andes.mercadolibre.com/924dc6ec5/p/55eb4c-thumbnail/b/26f535 | UI Specs}
 * @example
 * import { Thumbnail, ThumbnailMultiple } from '@andes/thumbnail';
 *
 * const MyComponent = () => (
 *  <ThumbnailMultiple
 *    modifier="circle"
 *    containerSize="56"
 *    type="grid"
 *    overflow={3}
 *  >
 *    <Thumbnail>
 *      <img alt="avatar" src="https://http2.mlstatic.com/path/to/some/image.webp" />
 *    </Thumbnail>
 *    <Thumbnail>
 *      <img alt="avatar" src="https://http2.mlstatic.com/path/to/some/image.webp" />
 *    </Thumbnail>
 *    <Thumbnail>
 *      <img alt="avatar" src="https://http2.mlstatic.com/path/to/some/image.webp" />
 *    </Thumbnail>
 *  </ThumbnailMultiple>
 * );
 */
export const ThumbnailMultiple: FunctionComponent<ThumbnailMultipleProps>;

export type ThumbnailHierarchy = Hierarchy;
export type ThumbnailSize = Size;
export type ThumbnailType = Type;
